<!DOCTYPE html>
<html lang="es">
<head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>RioNero | Gestión habitacional</title>
    <meta name="description" content="RioNero acompaña proyectos de vivienda, ampliación, mejoramiento y gestión de subsidios con enfoque social, técnico y territorial.">
    <style>
        :root{
            --primary:#61a7e8;
            --primary-dark:#3b86ca;
            --soft:#edf5fc;
            --gray:#b9c2cd;
            --text:#243241;
            --muted:#6a7788;
            --line:#dde5ee;
            --white:#ffffff;
            --bg:#f6f9fc;
            --shadow:0 18px 45px rgba(36,50,65,.10);
            --radius:22px;
            --container:1180px;
        }
        *{box-sizing:border-box}
        html{scroll-behavior:smooth}
        body{margin:0;font-family:Arial,Helvetica,sans-serif;color:var(--text);background:#fff;line-height:1.6}
        a{text-decoration:none;color:inherit}
        img{max-width:100%;display:block}
        .container{width:min(100% - 32px, var(--container));margin:0 auto}
        .header{position:sticky;top:0;z-index:999;background:rgba(255,255,255,.92);backdrop-filter:blur(10px);border-bottom:1px solid var(--line)}
        .nav{min-height:82px;display:flex;align-items:center;justify-content:space-between;gap:20px}
        .brand{display:flex;align-items:center;gap:14px;font-weight:800}
        .brand img{width:56px;height:56px;object-fit:contain;border-radius:50%;background:#f4f7fb;border:1px solid var(--line);padding:4px}
        .brand small{display:block;color:var(--muted);font-size:12px;font-weight:600;margin-top:2px}
        .menu{display:flex;gap:24px;font-size:15px;font-weight:700;color:var(--muted)}
        .menu a:hover{color:var(--primary-dark)}
        .hero{
            background:
                radial-gradient(circle at top left, rgba(97,167,232,.16), transparent 30%),
                radial-gradient(circle at bottom right, rgba(185,194,205,.20), transparent 30%),
                linear-gradient(180deg,#f8fbff 0%, #ffffff 100%);
            overflow:hidden;
        }
        .hero-grid{display:grid;grid-template-columns:1.1fr .9fr;gap:36px;align-items:center;min-height:70vh;padding:18px 0 18px}
        .eyebrow{display:inline-block;font-size:13px;font-weight:800;color:var(--primary-dark);background:rgba(97,167,232,.10);border:1px solid rgba(97,167,232,.20);border-radius:999px;padding:8px 14px;margin-bottom:18px}
        h1{margin:0 0 10px;font-size:clamp(1.3rem, 3vw, 2.2rem);line-height:1.1;letter-spacing:-1px}
        .hero p{margin:0;font-size:1.08rem;color:var(--muted);max-width:650px}
        .actions{display:flex;flex-wrap:wrap;gap:14px;margin-top:30px}
        .btn{display:inline-flex;align-items:center;justify-content:center;padding:14px 22px;border-radius:999px;font-weight:800;transition:.25s ease}
        .btn-primary{background:linear-gradient(135deg, var(--primary), var(--primary-dark));color:#fff;box-shadow:0 14px 30px rgba(97,167,232,.28)}
        .btn-secondary{border:1px solid var(--line);color:var(--text);background:#fff}
        .btn:hover{transform:translateY(-2px)}
        .hero-points{display:grid;grid-template-columns:repeat(3,1fr);gap:14px;margin-top:34px}
        .point{background:rgba(255,255,255,.80);border:1px solid var(--line);border-radius:18px;padding:18px;box-shadow:0 8px 20px rgba(36,50,65,.05)}
        .point strong{display:block;font-size:1.15rem;margin-bottom:6px}
        .point span{color:var(--muted);font-size:.95rem}
        .hero-image{position:relative}
        .hero-image .main{border-radius:28px;overflow:hidden;border:1px solid var(--line);box-shadow:var(--shadow)}
        .hero-image .main img{width:100%;height:440px;object-fit:cover;margin-top:0;}
        .floating{position:absolute;right:-10px;bottom:24px;width:min(90%, 320px);background:rgba(255,255,255,.96);border:1px solid var(--line);border-radius:22px;padding:20px;box-shadow:var(--shadow)}
        .floating h3{margin:0 0 8px;font-size:1.05rem}
        .floating p{margin:0;color:var(--muted);font-size:.95rem}
        section{padding:84px 0}
        .section-head{max-width:760px;margin-bottom:34px}
        .section-head span{display:inline-block;font-size:.8rem;font-weight:800;color:var(--primary-dark);letter-spacing:.08em;text-transform:uppercase;margin-bottom:12px}
        .section-head h2{margin:0 0 12px;font-size:clamp(1.9rem, 4vw, 3rem);line-height:1.1;letter-spacing:-1px}
        .section-head p{margin:0;color:var(--muted)}
        .grid-4,.grid-3,.steps,.contact-grid{display:grid;gap:22px}
        .grid-4{grid-template-columns:repeat(4,1fr)}
        .grid-3{grid-template-columns:repeat(3,1fr)}
        .steps{grid-template-columns:repeat(4,1fr)}
        .contact-grid{grid-template-columns:1.2fr .8fr;align-items:start}
        .card,.program-card,.project-card,.step-card,.contact-card{background:#fff;border:1px solid var(--line);border-radius:var(--radius);box-shadow:0 12px 30px rgba(36,50,65,.05);overflow:hidden}
        .card{padding:24px}
        .card-icon{width:54px;height:54px;display:grid;place-items:center;border-radius:16px;margin-bottom:16px;background:linear-gradient(135deg, rgba(97,167,232,.16), rgba(185,194,205,.22));color:var(--primary-dark);font-weight:800}
        .card h3,.program-card h3,.project-card h3,.step-card h3,.contact-card h3{margin:0 0 10px;font-size:1.1rem}
        .card p,.program-card p,.project-card p,.step-card p,.contact-card p{margin:0;color:var(--muted)}
        .alt-bg{background:var(--bg)}
        .program-card img,.project-card img{width:100%;height:220px;object-fit:cover;background:#ebeff4}
        .copy{padding:22px}
        .placeholder{display:inline-block;margin-top:12px;font-size:.82rem;font-weight:700;color:var(--primary-dark);background:rgba(97,167,232,.10);padding:8px 12px;border-radius:999px}
        .step-number{width:46px;height:46px;display:grid;place-items:center;border-radius:50%;background:linear-gradient(135deg, var(--primary), var(--primary-dark));color:#fff;font-weight:800;margin:22px 0 0 22px;box-shadow:0 10px 24px rgba(97,167,232,.25)}
        .impact{display:grid;grid-template-columns:repeat(4,1fr);gap:18px;margin-top:24px}
        .metric{text-align:center;background:linear-gradient(180deg, #fff, #f8fbff);border:1px solid var(--line);border-radius:20px;padding:24px;box-shadow:0 12px 28px rgba(36,50,65,.04)}
        .metric strong{display:block;font-size:2rem;color:var(--primary-dark);margin-bottom:6px}
        .metric span{color:var(--muted);font-weight:700}
        .cta{background:linear-gradient(135deg, #eaf4ff, #f7f9fc);border:1px solid var(--line);border-radius:30px;padding:36px;display:flex;align-items:center;justify-content:space-between;gap:24px;box-shadow:var(--shadow)}
        .cta h3{margin:0 0 10px;font-size:clamp(1.5rem, 3vw, 2.3rem);line-height:1.1}
        .cta p{margin:0;color:var(--muted);max-width:680px}
        .contact-list{display:grid;gap:14px;margin-top:16px}
        .contact-item{display:flex;gap:12px;align-items:flex-start;color:var(--muted)}
        .contact-item strong{display:block;color:var(--text);margin-bottom:2px}
        .form{display:grid;gap:14px}
        .field{display:grid;gap:8px}
        label{font-size:.94rem;font-weight:700}
        input, textarea{width:100%;border:1px solid var(--line);border-radius:16px;padding:14px 16px;font:inherit;background:#fff;outline:none}
        textarea{min-height:140px;resize:vertical}
        input:focus, textarea:focus{border-color:rgba(97,167,232,.7);box-shadow:0 0 0 4px rgba(97,167,232,.12)}
        .note{margin-top:14px;padding:16px 18px;border-radius:16px;background:rgba(97,167,232,.08);border:1px dashed rgba(97,167,232,.25);color:var(--muted);font-size:.94rem}
        footer{padding:28px 0 42px;color:var(--muted);font-size:.95rem}
        .footer-row{display:flex;justify-content:space-between;align-items:center;gap:16px;padding-top:16px;border-top:1px solid var(--line)}
        @media (max-width:1080px) {
            .hero-grid,.grid-4,.grid-3,.steps,.impact,.contact-grid{grid-template-columns:repeat(2,1fr)}
        }
        @media (max-width:760px) {
            .nav{flex-wrap:wrap;padding:14px 0}
            .menu{width:100%;overflow:auto;gap:16px;padding-bottom:4px}
            .hero-grid,.grid-4,.grid-3,.steps,.impact,.contact-grid,.hero-points{grid-template-columns:1fr}
            .hero-grid{gap:18px;min-height:unset;padding:8px 0 8px}
            .hero-image .main img{height:220px;max-height:60vw;margin-top:0;}
            .cta,.footer-row{flex-direction:column;align-items:flex-start}
            section{padding:38px 0}
            .container{padding-left:8px;padding-right:8px}
            .actions{flex-direction:column;gap:10px}
            .btn, .btn-primary, .btn-secondary{width:100%;min-width:0;box-sizing:border-box}
            .form{gap:10px}
            .field input, .field textarea{font-size:1rem}
            .hero-points{gap:10px}
            .program-card img, .project-card img{height:120px}
            .step-number{margin:12px 0 0 12px;width:36px;height:36px;font-size:1rem}
            .metric{padding:14px}
            .note{font-size:.9rem;padding:10px}
            .footer-row{gap:8px}
        }
        @media (max-width:480px) {
            h1, .section-head h2, .cta h3 {font-size:1.3rem !important;}
            .hero-image .main img{height:10px;}
            .program-card img, .project-card img{height:80px;}
            .container{padding-left:2px;padding-right:2px}
            .btn, .btn-primary, .btn-secondary{font-size:.98rem;padding:10px 8px}
            .step-number{width:28px;height:28px;font-size:.9rem}
        }
    </style>
</head>
